        LD A,(DE)                        ; $07A6  1A
        SBC A,B                          ; $07A7  98
        LD H,A                           ; $07A8  67
        RET                              ; $07A9  C9
; [AI] 16-bit compare of an 8-bit value (in A) against the word at (DE): subtracts to set
;       carry/produce a difference in HL, used in the address-bound and first-address comparisons.
SUB_07AA:
        LD L,A                           ; $07AA  6F
        LD H,$00                         ; $07AB  26 00
        LD A,(DE)                        ; $07AD  1A
        SUB L                            ; $07AE  95
        LD L,A                           ; $07AF  6F
        INC DE                           ; $07B0  13
